package github.chains;

import com.github.javaparser.JavaParser;
import com.github.javaparser.ParseResult;
import com.github.javaparser.ParserConfiguration;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.ImportDeclaration;
import com.github.javaparser.ast.Modifier;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.BinaryExpr;
import com.github.javaparser.ast.expr.Expression;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.expr.UnaryExpr;
import com.github.javaparser.ast.stmt.BlockStmt;
import com.github.javaparser.ast.stmt.IfStmt;
import com.github.javaparser.ast.stmt.Statement;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;
import com.github.javaparser.utils.SourceRoot;

import java.io.File;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Arrays;
import java.util.List;

public class Main {

    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-directory>");
            System.exit(1);
        }

        Path sourceDir = Paths.get(args[0]);
        SourceRoot sourceRoot = new SourceRoot(sourceDir);

        ParserConfiguration config = new ParserConfiguration();
        config.setLanguageLevel(ParserConfiguration.LanguageLevel.JAVA_17);
        JavaParser javaParser = new JavaParser(config);
        sourceRoot.setParserConfiguration(config);

        sourceRoot.findAll(CompilationUnit.class).forEach(cu -> {
            new IsAllBlankFixer().visit(cu, null);
            new ClientHelperFixer().visit(cu, null);
        });

        sourceRoot.saveAll();
        System.out.println("Transformation complete!");
    }

    static class IsAllBlankFixer extends VoidVisitorAdapter<Void> {
        @Override
        public void visit(MethodCallExpr n, Void arg) {
            super.visit(n, arg);

            if (isIsAllBlankCall(n)) {
                Expression replacement = createIsAllBlankReplacement(n);
                n.replace(replacement);
            }
        }

        private boolean isIsAllBlankCall(MethodCallExpr methodCall) {
            if (methodCall.getName().asString().equals("isAllBlank")) {
                String scope = methodCall.getScope()
                        .map(s -> s.toString())
                        .orElse("");
                return scope.contains("StringUtils") || scope.isEmpty();
            }
            return false;
        }

        private Expression createIsAllBlankReplacement(MethodCallExpr methodCall) {
            List<Expression> args = methodCall.getArguments();
            if (args.isEmpty()) {
                return methodCall;
            }

            Expression result = createIsBlankCheck(args.get(0));

            for (int i = 1; i < args.size(); i++) {
                result = new BinaryExpr(
                        result,
                        createIsBlankCheck(args.get(i)),
                        BinaryExpr.Operator.AND
                );
            }

            return result;
        }

        private Expression createIsBlankCheck(Expression arg) {
            return new MethodCallExpr("isBlank", arg);
        }

        @Override
        public void visit(ImportDeclaration n, Void arg) {
            super.visit(n, arg);
            if (n.getNameAsString().equals("org.apache.commons.lang3.StringUtils.isAllBlank")) {
                n.remove();
            }
        }
    }

    static class ClientHelperFixer extends VoidVisitorAdapter<Void> {
        @Override
        public void visit(MethodCallExpr n, Void arg) {
            super.visit(n, arg);

            if (n.getName().asString().equals("new ClientHelper") ||
                (n.getScope().isPresent() && n.getScope().get().toString().contains("ClientHelper"))) {
            }
        }

        @Override
        public void visit(CompilationUnit cu, Void arg) {
            super.visit(cu, arg);

            cu.findAll(MethodCallExpr.class).forEach(methodCall -> {
                if (isClientHelperConstructor(methodCall)) {
                    fixClientHelperConstructor(methodCall);
                }
            });
        }

        private boolean isClientHelperConstructor(MethodCallExpr methodCall) {
            if (methodCall.getName().asString().equals("ClientHelper")) {
                return true;
            }
            if (methodCall.getScope().isPresent()) {
                String scope = methodCall.getScope().get().toString();
                return scope.contains("new ClientHelper");
            }
            return false;
        }

        private void fixClientHelperConstructor(MethodCallExpr methodCall) {
            List<Expression> args = methodCall.getArguments();
            if (args.size() >= 4) {
                Expression firstArg = args.get(0);
                if (firstArg instanceof NameExpr) {
                    NameExpr nameExpr = (NameExpr) firstArg;
                    String varName = nameExpr.getNameAsString();

                    Expression newFirstArg = new MethodCallExpr(
                            new NameExpr("build"),
                            "getParent"
                    );

                    methodCall.setArgument(0, newFirstArg);
                }
            }
        }
    }
}

